<template>
  <div class="pricing-view">
    <PricingOptions
      :pricingServices="pricingServices"
      @option-selected="updateSelection"
    />
    <PricingTableSection
      v-if="filteredPricingObject"
      :activeService="filteredPricingObject"
      :key="selectedService"
    />
  </div>
</template>

<script>
import PricingOptions from '@/components/pricing/OptionsSection.vue';
import PricingTableSection from '@/components/pricing/PricingTableSection.vue';
import pricingData from '@/data/pricing.json';

export default {
  name: 'PricingView',
  components: {
    PricingOptions,
    PricingTableSection,
  },
  data() {
    return {
      pricingServices: pricingData.pricing.map(item => item.service),
      selectedService: pricingData.pricing[1].service,
      rawPricingData: pricingData
    };
  },
  computed: {
    filteredPricingObject() {
      return this.rawPricingData.pricing.find(
        (item) => item.service === this.selectedService
      );
    }
  },
  methods: {
    updateSelection(value) {
      this.selectedService = value;
    }
  }
};
</script>
