<template>
  <div class="options-section">
    <div class="options-section-title">{{ propsTitle }}</div>

    <div class="options-container">
      <button
        v-for="(service, index) in actualOptions"
        :key="index"
        class="option-button"
        :class="{ active: activeOption === service }"
        @click="toggleOption(service)"
      >
        {{ service }}
      </button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'PricingOptions',
  props: {
    propsTitle: { type: String, default: 'Pricing Options' },
    pricingServices: { type: Array, required: true }
  },
  computed: {
    // This fixes the "all in one button" issue by making sure 
    // we are grabbing the array even if it's nested or proxied weirdly
    actualOptions() {
      if (!this.pricingServices) return [];
      
      // If the first element is an array
      if (Array.isArray(this.pricingServices[0])) {
        return this.pricingServices[0];
      }
      
      // If the first element is an object containing the array
      if (this.pricingServices.pricingServices) {
        return this.pricingServices.pricingServices;
      }

      return this.pricingServices;
    }
  },
  data() {
    return {
      activeOption: null
    };
  },
  watch: {
    // Set the default once the dynamic data actually arrives
    actualOptions: {
      immediate: true,
      handler(newVal) {
        if (newVal && newVal.length > 0 && !this.activeOption) {
          this.activeOption = newVal[1];
        }
      }
    }
  },
  methods: {
    toggleOption(service) {
      this.activeOption = service;
      this.$emit('option-selected', service);
    }
  }
};
</script>